// Fetch full volunteer details
const fetchUserProfile = async (userId: string) => {
  try {
    const { data, error } = await supabase
      .from("user_roles")
      .select("*")
      .eq("id", userId)
      .single();
    if (!error && data) {
      setProfileData(data);
    }
  } catch (err) {
    console.error("Error fetching user profile:", err);
  }
};
